---
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"li"> {
  class?: string;
}

const {
  class: className = "",
  ...rest
} = Astro.props as Props;

const itemVariants = cva("inline-flex items-center");
---

<li
  {...rest}
  data-slot="breadcrumb-item"
  class={cn("gap-1", itemVariants(), className)}
>
  <slot />
</li>

---
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"ol"> {
  class?: string;
}

const {
  class: className = "",
  ...rest
} = Astro.props as Props;

const listVariants = cva(
  "flex flex-wrap items-center wrap-break-word",
);
---

<ol
  {...rest}
  data-slot="breadcrumb-list"
  class={cn("text-muted-foreground gap-1.5 text-xs/relaxed", listVariants(), className)}
>
  <slot />
</ol>

---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"li"> {
  class?: string;
}

const {
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<li
  {...rest}
  role="presentation"
  aria-hidden="true"
  data-slot="breadcrumb-separator"
  class={cn("[&>svg]:size-3.5", className)}
>
  <slot>
    <SemanticIcon name="chevron-right" class="" />
  </slot>
</li>

export { default as Breadcrumb } from "./Breadcrumb.astro";
export { default as BreadcrumbList } from "./BreadcrumbList.astro";
export { default as BreadcrumbItem } from "./BreadcrumbItem.astro";
export { default as BreadcrumbSeparator } from "./BreadcrumbSeparator.astro";
